    43→  isIdle: boolean;
    44→
    45→  /**
    46→   * Timestamp when user went idle (null if not idle)
    47→   */
    48→  idleSince: number | null;
    49→
    50→  /**
    51→   * Current idle duration in milliseconds
    52→   */
    53→  idleDuration: number;
    54→
