    64→ * Hook for detecting user idle state
    65→ */
    66→export function useIdleDetection(config: IdleDetectionConfig): IdleDetectionState {
    67→  const { threshold = DEFAULT_THRESHOLD, enabled = false, onIdle, onReturn } = config;
    68→
    69→  const [isIdle, setIsIdle] = useState(false);
    70→  const [idleSince, setIdleSince] = useState<number | null>(null);
    71→  const [lastActivity, setLastActivity] = useState(Date.now());
    72→
    73→  const idleTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    74→  const isIdleRef = useRef(false);
    75→  const onIdleCallbackRef = useRef(onIdle);
    76→  const onReturnCallbackRef = useRef(onReturn);
    77→
    78→  // Update callback refs when they change
    79→  useEffect(() => {
    80→    onIdleCallbackRef.current = onIdle;
    81→    onReturnCallbackRef.current = onReturn;
    82→  }, [onIdle, onReturn]);
    83→
    84→  /**
    85→   * Reset idle timer (user activity detected)
    86→   */
    87→  const resetIdleTimer = useCallback(() => {
    88→    if (!enabled) return;
    89→
    90→    const now = Date.now();
    91→    setLastActivity(now);
    92→
    93→    // If was idle, trigger return callback
    94→    if (isIdleRef.current && idleSince !== null) {
    95→      const idleTime = now - idleSince;
    96→      onReturnCallbackRef.current?.(idleTime);
    97→      setIsIdle(false);
    98→      setIdleSince(null);
    99→      isIdleRef.current = false;
   100→    }
   101→
   102→    // Clear existing timer
   103→    if (idleTimerRef.current) {
   104→      clearTimeout(idleTimerRef.current);
   105→    }
   106→
   107→    // Set new timer
   108→    idleTimerRef.current = setTimeout(() => {
   109→      const idleStart = Date.now();
   110→      setIsIdle(true);
   111→      setIdleSince(idleStart);
   112→      isIdleRef.current = true;
   113→      onIdleCallbackRef.current?.(0);
   114→    }, threshold);
   115→  }, [enabled, threshold, idleSince]);
   116→
   117→  /**
   118→   * Activity event handlers
   119→   */
   120→  useEffect(() => {
   121→    if (!enabled) {
   122→      // Clean up when disabled
   123→      if (idleTimerRef.current) {
   124→        clearTimeout(idleTimerRef.current);
   125→      }
   126→      setIsIdle(false);
   127→      setIdleSince(null);
   128→      isIdleRef.current = false;
   129→      return;
   130→    }
   131→
   132→    const events = ['mousemove', 'keydown', 'mousedown', 'touchstart', 'scroll'];
   133→
   134→    // Throttle activity detection to avoid excessive updates
   135→    let throttleTimer: ReturnType<typeof setTimeout> | null = null;
   136→    const throttledReset = () => {
   137→      if (throttleTimer) return;
   138→      throttleTimer = setTimeout(() => {
   139→        resetIdleTimer();
   140→        throttleTimer = null;
   141→      }, 1000); // Throttle to max once per second
   142→    };
   143→
   144→    // Add event listeners
   145→    events.forEach(event => {
   146→      window.addEventListener(event, throttledReset, { passive: true });
   147→    });
   148→
   149→    // Page visibility change handler
   150→    const handleVisibilityChange = () => {
   151→      if (document.visibilityState === 'visible') {
   152→        resetIdleTimer();
   153→      }
   154→    };
   155→    document.addEventListener('visibilitychange', handleVisibilityChange);
   156→
   157→    // Initialize timer
   158→    resetIdleTimer();
   159→
   160→    // Cleanup
   161→    return () => {
   162→      events.forEach(event => {
   163→        window.removeEventListener(event, throttledReset);
   164→      });
   165→      document.removeEventListener('visibilitychange', handleVisibilityChange);
   166→      if (idleTimerRef.current) {
   167→        clearTimeout(idleTimerRef.current);
   168→      }
   169→      if (throttleTimer) {
   170→        clearTimeout(throttleTimer);
   171→      }
   172→    };
   173→  }, [enabled, resetIdleTimer]);
