   175→  // Calculate current idle duration
   176→  const idleDuration = isIdle && idleSince !== null ? Date.now() - idleSince : 0;
   177→
   178→  return {
   179→    isIdle,
   180→    idleSince,
   181→    idleDuration,
   182→    lastActivity
   183→  };
