   809→              projectColor: project?.color || '#94A3B8', // Default gray
   810→              totalDuration: 0,
   811→              entryCount: 0,
   812→              percentage: 0
   813→            });
   814→          }
   815→
   816→          const summary = projectMap.get(projectId)!;
   817→          summary.totalDuration += entry.duration;
   818→          summary.entryCount += 1;
   819→        });
   820→
   821→        // Calculate percentages
   822→        const projectBreakdown = Array.from(projectMap.values()).map(summary => ({
   823→          ...summary,
   824→          percentage: totalTime > 0 ? (summary.totalDuration / totalTime) * 100 : 0
   825→        }));
   826→
   827→        // Sort by duration descending
   828→        projectBreakdown.sort((a, b) => b.totalDuration - a.totalDuration);
   829→
   830→        return {
   831→          year,
   832→          month,
   833→          totalDuration: totalTime,
   834→          entryCount: entries.length,
   835→          dailyBreakdown,
