   903→          }) : '';
   904→
   905→          // Format duration as HH:MM
   906→          const hours = Math.floor(entry.duration / 3600);
   907→          const minutes = Math.floor((entry.duration % 3600) / 60);
   908→          const duration = `${hours}h ${minutes.toString().padStart(2, '0')}m`;
   909→
   910→          const project = entry.projectId
   911→            ? projects.find(p => p.id === entry.projectId)?.name || ''
   912→            : '';
   913→
   914→          // Escape commas and quotes in text fields
   915→          const escapeCSV = (str: string) => {
   916→            if (!str) return '';
